async getOrderStatistics(
  startDate: Date,
  endDate: Date,
  sellerId?: string
): Promise<OrderStatistics> {
  const queryBuilder = this.orderRepository
    .createQueryBuilder('order')
    .where('order.createdAt BETWEEN :startDate AND :endDate', {
      startDate,
      endDate,
    });

  // Filtrer par vendeur si nécessaire
  if (sellerId) {
    queryBuilder.andWhere('order.sellerId = :sellerId', { sellerId });
  }

  // Ne compter que les commandes payées ou livrées
  queryBuilder.andWhere('order.status IN (:...statuses)', {
    statuses: [OrderStatus.PAID, OrderStatus.SHIPPED, OrderStatus.DELIVERED],
  });

  const result = await queryBuilder
    .select([
      'COUNT(order.id) as totalOrders',
      'SUM(order.total) as totalRevenue',
    ])
    .getRawOne();

  const totalOrders = parseInt(result.totalOrders) || 0;
  const totalRevenue = parseFloat(result.totalRevenue) || 0;
  const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

  return {
    totalOrders,
    totalRevenue,
    averageOrderValue,
  };
}
