// Définition des transitions autorisées
const allowedTransitions: Record<OrderStatus, OrderStatus[]> = {
  [OrderStatus.PENDING]: [OrderStatus.PAID, OrderStatus.CANCELLED],
  [OrderStatus.PAID]: [OrderStatus.SHIPPED, OrderStatus.CANCELLED],
  [OrderStatus.SHIPPED]: [OrderStatus.DELIVERED, OrderStatus.CANCELLED],
  [OrderStatus.DELIVERED]: [],
  [OrderStatus.CANCELLED]: [],
};

async updateOrderStatus(
  orderId: string,
  newStatus: OrderStatus,
  userId: string,
  userRole: string
): Promise<Order> {
  const order = await this.orderRepository.findOne({
    where: { id: orderId },
    relations: ['user'],
  });

  if (!order) {
    throw new NotFoundException('Commande non trouvée');
  }

  // Vérification des autorisations
  if (userRole !== 'admin' && order.sellerId !== userId) {
    throw new ForbiddenException(
      'Vous n\'êtes pas autorisé à modifier cette commande'
    );
  }

  // Vérification de la transition
  const allowed = allowedTransitions[order.status];
  if (!allowed.includes(newStatus)) {
    throw new BadRequestException(
      `Transition de ${order.status} vers ${newStatus} non autorisée`
    );
  }

  // Logique supplémentaire selon le nouveau statut
  if (newStatus === OrderStatus.CANCELLED && order.status !== OrderStatus.PENDING) {
    // Remboursement si la commande était déjà payée
    await this.refundOrder(order);
  }

  if (newStatus === OrderStatus.SHIPPED) {
    // Générer un numéro de suivi
    order.trackingNumber = this.generateTrackingNumber();
  }

  order.status = newStatus;
  await this.orderRepository.save(order);

  // Envoyer une notification par email
  await this.notificationService.notifyStatusChange(order, newStatus);

  return order;
}
