async getSellerOrders(
  sellerId: string,
  filters: OrderFiltersDto
): Promise<PaginatedResult<Order>> {
  const { page = 1, limit = 10, status, dateFrom, dateTo, search, minAmount, maxAmount } = filters;

  const query = this.orderRepository
    .createQueryBuilder('order')
    .leftJoinAndSelect('order.user', 'user')
    .where('order.sellerId = :sellerId', { sellerId });

  // Filtre par statut
  if (status) {
    query.andWhere('order.status = :status', { status });
  }

  // Filtre par période
  if (dateFrom) {
    query.andWhere('order.createdAt >= :dateFrom', { dateFrom });
  }
  if (dateTo) {
    query.andWhere('order.createdAt <= :dateTo', { dateTo });
  }

  // Recherche par client
  if (search) {
    query.andWhere(
      '(user.firstName ILIKE :search OR user.lastName ILIKE :search OR user.email ILIKE :search)',
      { search: `%${search}%` }
    );
  }

  // Filtre par montant
  if (minAmount) {
    query.andWhere('order.total >= :minAmount', { minAmount });
  }
  if (maxAmount) {
    query.andWhere('order.total <= :maxAmount', { maxAmount });
  }

  // Pagination
  const [data, total] = await query
    .orderBy('order.createdAt', 'DESC')
    .skip((page - 1) * limit)
    .take(limit)
    .getManyAndCount();

  return {
    data,
    meta: {
      total,
      page,
      lastPage: Math.ceil(total / limit),
      limit,
    },
  };
}
