async exportOrdersToCSV(
  sellerId: string,
  filters: OrderFiltersDto
): Promise<string> {
  // Récupérer toutes les commandes (sans pagination)
  const orders = await this.orderRepository
    .createQueryBuilder('order')
    .leftJoinAndSelect('order.user', 'user')
    .leftJoinAndSelect('order.items', 'items')
    .where('order.sellerId = :sellerId', { sellerId })
    .applyFilters(filters) // Application des mêmes filtres
    .getMany();

  // Définir les colonnes CSV
  const csvColumns = [
    'ID Commande',
    'Client',
    'Email',
    'Date',
    'Statut',
    'Total (FCFA)',
    'Articles',
  ];

  const csvRows = orders.map(order => [
    order.id,
    `${order.user.firstName} ${order.user.lastName}`,
    order.user.email,
    order.createdAt.toISOString().split('T')[0],
    order.status,
    order.total.toFixed(2),
    order.items.map(i => `${i.quantity}x ${i.productName}`).join(', '),
  ]);

  // Générer le CSV
  const csvContent = [csvColumns, ...csvRows]
    .map(row => row.map(cell => `"${cell}"`).join(','))
    .join('\n');

  // Sauvegarder temporairement
  const filename = `orders_${sellerId}_${Date.now()}.csv`;
  const filepath = path.join('/tmp', filename);
  await fs.promises.writeFile(filepath, csvContent, 'utf-8');

  // Option: uploader vers S3 et retourner URL
  const fileUrl = await this.storageService.upload(`exports/${filename}`, filepath);

  // Nettoyage après 1 heure (cron job)
  setTimeout(() => fs.promises.unlink(filepath).catch(() => {}), 3600000);

  return fileUrl;
}
